-- Amb Epic Gold WF Review -> SYS-0002 (status_update, 2026-02-17)
INSERT INTO notes (organization_id, initiative_id, note_text, note_type, author, created_at) SELECT '00000000-0000-0000-0000-000000000001', 'c963e850-439a-4b62-9fe2-d36e43d6741c', 'Attached known standards for SDOH and MA ordering Scope of Practice. Shawna is working on this with Nancy Olson WA-Tacoma. More work needs to be done on this. We don''t have a system standard defined. Shawna interested in establishing a system EHR standard though. This apparently has been discussed, to formally document and apply to all MAs in the role. There is some guidance that if system has a policy and standards, then this can be accomplished. Other than that, Shawna informed me that for Nebraska and some other states they don''t use MAs. They use EMTs, CNAs, and Medical Staff Assistants (MSAs), All of those scopes need to be defined as well.', 'status_update', 'Marty Koepke', '2026-02-17T22:33:44.934+00:00' WHERE NOT EXISTS (SELECT 1 FROM notes WHERE initiative_id = 'c963e850-439a-4b62-9fe2-d36e43d6741c' AND note_text = 'Attached known standards for SDOH and MA ordering Scope of Practice. Shawna is working on this with Nancy Olson WA-Tacoma. More work needs to be done on this. We don''t have a system standard defined. Shawna interested in establishing a system EHR standard though. This apparently has been discussed, to formally document and apply to all MAs in the role. There is some guidance that if system has a policy and standards, then this can be accomplished. Other than that, Shawna informed me that for Nebraska and some other states they don''t use MAs. They use EMTs, CNAs, and Medical Staff Assistants (MSAs), All of those scopes need to be defined as well.' AND created_at = '2026-02-17T22:33:44.934+00:00');
