-- SDOH CSH Standards -> SYS-0006 (general, 2026-02-18)
INSERT INTO notes (organization_id, initiative_id, note_text, note_type, author, created_at) SELECT '00000000-0000-0000-0000-000000000001', 'd83e591b-dede-4478-9094-cc125aa0896e', 'Per Dawn: There are now CMS requirements around Age Friendly. Focus now is "are we meeting it" attestation. Both EHRs did have standard content and we did not take it. That was under Karen Darling. Part of current work is evaluating if we can or what can/should we take to get caught up. 5 domains: Pt. Goals/ACP, Pt Meds, Frailty Screening (malnutrition, depression, mobility, etc.)....pulls into a navigator for quality, Social Screening (access, abuse, caregiver stress, needs) social isolation is not consistent and not in Gold, financial abuse). potential request is to expand screening questions for patients > 65. last domain is leadership (this is where CMS wants to know if someone in the Org is responsible, monitoring imp. and utilization of program).', 'general', 'Marty Koepke', '2026-02-18T17:41:04.702+00:00' WHERE NOT EXISTS (SELECT 1 FROM notes WHERE initiative_id = 'd83e591b-dede-4478-9094-cc125aa0896e' AND note_text = 'Per Dawn: There are now CMS requirements around Age Friendly. Focus now is "are we meeting it" attestation. Both EHRs did have standard content and we did not take it. That was under Karen Darling. Part of current work is evaluating if we can or what can/should we take to get caught up. 5 domains: Pt. Goals/ACP, Pt Meds, Frailty Screening (malnutrition, depression, mobility, etc.)....pulls into a navigator for quality, Social Screening (access, abuse, caregiver stress, needs) social isolation is not consistent and not in Gold, financial abuse). potential request is to expand screening questions for patients > 65. last domain is leadership (this is where CMS wants to know if someone in the Org is responsible, monitoring imp. and utilization of program).' AND created_at = '2026-02-18T17:41:04.702+00:00');
