-- Interpreter Services Optimization -> SYS-0005 (general, 2026-02-20)
INSERT INTO notes (organization_id, initiative_id, note_text, note_type, author, created_at) SELECT '00000000-0000-0000-0000-000000000001', '6cced172-82eb-4f1c-907f-7d05a905d9a2', 'Email from Lisa: I am writing to ensure we are coordinating our efforts regarding the EHR language updates.

I have been working with the NW region to address a Department of Justice lawsuit, which requires specific EHR changes to ensure compliance. During our last meeting, we discussed consolidating our efforts to ensure these updates are implemented consistently across the board, and in a timely manner.

My Supply Chain partner is currently reviewing vendor data to produce actionable materials for the project. In the meantime, I want to ensure we are aligned and prepared to move forward together.

Please let me know if there are any additional steps I should complete at this stage.', 'general', 'Marty Koepke', '2026-02-20T19:58:13.351+00:00' WHERE NOT EXISTS (SELECT 1 FROM notes WHERE initiative_id = '6cced172-82eb-4f1c-907f-7d05a905d9a2' AND note_text = 'Email from Lisa: I am writing to ensure we are coordinating our efforts regarding the EHR language updates.

I have been working with the NW region to address a Department of Justice lawsuit, which requires specific EHR changes to ensure compliance. During our last meeting, we discussed consolidating our efforts to ensure these updates are implemented consistently across the board, and in a timely manner.

My Supply Chain partner is currently reviewing vendor data to produce actionable materials for the project. In the meantime, I want to ensure we are aligned and prepared to move forward together.

Please let me know if there are any additional steps I should complete at this stage.' AND created_at = '2026-02-20T19:58:13.351+00:00');
